mapper.update:
update knowledge_document
document_name=#{documentName}, embed_id=#{embedId}, type=#{type, typeHandler=top.emilejones.hhu.knowledge.handler.KnowledgeDocumentTypeHandler}, isdelete=#{isDelete}, create_time=#{createTime}
where document_id=#{documentId} and isdelete=1

mapper.select:
select * from knowledge_document where document_id in (
    select document_id from collection_document where kb_id=#{knowledgeCatalogId}
)
order by create_time desc
limit #{limit} offset #{offset}
